UPDATE TBOT_POINT_NEW_BOSS
   SET CUR_HP     = #{newHp,    jdbcType=NUMERIC}
     , CUR_HP_EXT = #{newHpExt, jdbcType=VARCHAR}
     , END_YN     = #{endYn,    jdbcType=VARCHAR}
     , PROC_DATE  = SYSDATE
     , CLOSE_DATE = SYSDATE

     , DEBUFF = DEBUFF + ${heavensPunishment} * 10


     , DEBUFF = DEBUFF - 1


     , DEBUFF1 = DEBUFF1 + 5


     , DEBUFF1 = DEBUFF1 - 1

 WHERE SEQ    = #{seq, jdbcType=NUMERIC}
   AND CUR_HP  = #{hp, jdbcType=NUMERIC}
   AND END_YN = '0'

mapper.insert:
INSERT INTO TBOT_POINT_NEW_BOSS
    (SEQ
    ,INSERT_DATE
    ,END_YN
    ,ATK_RATE
    ,ATK_POWER
    ,DEF_RATE
    ,DEF_POWER
    ,EVADE_RATE
    ,CRIT_DEF_RATE
    ,DEBUFF
    ,DEBUFF1
    ,DEBUFF2
    ,REWARD
    ,MAX_HP
    ,MAX_HP_EXT
    ,CUR_HP
    ,CUR_HP_EXT
    ,HIDE_RULE
    ,PATTERN
    ,REWARD_TYPE
    ,BOSS_TYPE
    ,CLOSE_DATE)
SELECT NVL(MAX(SEQ), 0) + 1
      ,TO_DATE(#{startDate, jdbcType=VARCHAR},'yyyy-mm-dd hh24:mi:ss')
      ,'0'
      ,#{atkRate,     jdbcType=NUMERIC}
      ,#{atkPower,    jdbcType=NUMERIC}
      ,#{defRate,     jdbcType=NUMERIC}
      ,#{defPower,    jdbcType=NUMERIC}
      ,#{evadeRate,   jdbcType=NUMERIC}
      ,#{critDefRate, jdbcType=NUMERIC}
      ,0
      ,0
      ,0
      ,0
      ,#{maxHp,       jdbcType=NUMERIC}
      ,#{maxHpExt,    jdbcType=VARCHAR}
      ,#{maxHp,       jdbcType=NUMERIC}
      ,#{maxHpExt,    jdbcType=VARCHAR}
      ,#{hideRule,    jdbcType=VARCHAR}
      ,#{pattern,     jdbcType=VARCHAR}
      ,#{rewardType,  jdbcType=VARCHAR}
      ,#{bossType,    jdbcType=VARCHAR}
      ,NULL
  FROM TBOT_POINT_NEW_BOSS

mapper.update:
UPDATE TBOT_POINT_NEW_BOSS
   SET CUR_HP    = CUR_HP + #{rawDmg, jdbcType=NUMERIC}
     , PROC_DATE = SYSDATE
 WHERE SEQ    = #{seq, jdbcType=NUMERIC}
   AND END_YN = '0'

UPDATE TBOT_POINT_NEW_BOSS
   SET BOSS_TYPE     = #{bossType,    jdbcType=VARCHAR}
     , ATK_RATE      = #{atkRate,     jdbcType=NUMERIC}
     , ATK_POWER     = #{atkPower,    jdbcType=NUMERIC}
     , DEF_RATE      = #{defRate,     jdbcType=NUMERIC}
     , DEF_POWER     = #{defPower,    jdbcType=NUMERIC}
     , EVADE_RATE    = #{evadeRate,   jdbcType=NUMERIC}
     , CRIT_DEF_RATE = #{critDefRate, jdbcType=NUMERIC}
     , MAX_HP        = #{maxHp,       jdbcType=NUMERIC}
     , MAX_HP_EXT    = #{maxHpExt,    jdbcType=VARCHAR}
     , CUR_HP        = #{curHp,        jdbcType=NUMERIC}
     , CUR_HP_EXT    = #{curHpExt,    jdbcType=VARCHAR}
     , DEBUFF        = 0
     , DEBUFF1       = 0
     , DEBUFF2       = 0
     , PROC_DATE     = SYSDATE
     , CLOSE_DATE = TO_DATE(#{closeDate}, 'yyyymmdd hh24miss')
 WHERE SEQ = (SELECT MAX(SEQ) FROM TBOT_POINT_NEW_BOSS WHERE END_YN = '0')
   AND END_YN = '0'
